class Solution:
    def primePalindrome(self, n: int) -> int:
        def is_prime(num: int) -> bool:
            if num < 2:
                return False
            for i in range(2, int(num ** 0.5) + 1):
                if num % i == 0:
                    return False
            return True

        def is_palindrome(num: int) -> bool:
            return str(num) == str(num)[::-1]

        while True:
            if is_prime(num) and is_palindrome(num):
                return num
            num += 1
